/* Global KPI breakdown modal — used by every St card via context */
const KpiInfoCtx = createContext(null);
function KpiInfoProvider({children}){
  const [info,setInfo]=useState(null);
  return (<KpiInfoCtx.Provider value={{info,setInfo}}>
    {children}
    {info&&<div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/40 p-4" onClick={()=>setInfo(null)}>
      <div className="bg-white w-full max-w-2xl rounded-2xl overflow-hidden" onClick={e=>e.stopPropagation()}>
        <div className="px-6 py-4 border-b border-stone-200 bg-blue-50 flex items-start justify-between">
          <div className="flex-1">
            <div className="text-[10px] uppercase tracking-wider text-blue-700 font-bold">{info.label}</div>
            <div className="text-2xl font-bold text-blue-900 mt-0.5">{info.value}</div>
            {info.formula&&<div className="text-xs text-blue-700 mt-1.5 italic">{info.formula}</div>}
          </div>
          <button onClick={()=>setInfo(null)} className="p-1.5 hover:bg-white/40 rounded-full"><Xx className="w-4 h-4"/></button>
        </div>
        <div className="p-6 space-y-4 max-h-[60vh] overflow-y-auto">
          {info.description&&<div className="text-sm text-stone-700 leading-relaxed">{info.description}</div>}
          {info.source&&<div className="bg-stone-50 rounded-xl p-3 text-xs">
            <div className="font-bold uppercase tracking-wider text-stone-500 mb-1">Source</div>
            <div className="text-stone-700">{info.source}</div>
          </div>}
          {info.items&&info.items.length>0&&<div>
            <div className="text-xs font-bold uppercase tracking-wider text-stone-500 mb-2">Items contributing to this number ({info.items.length})</div>
            <div className="border border-stone-200 rounded-xl overflow-hidden divide-y divide-stone-100">
              {info.items.slice(0,30).map((it,i)=><div key={i} className="px-4 py-2.5 flex items-center justify-between gap-3 hover:bg-stone-50">
                <div className="min-w-0 flex-1">
                  <div className="text-sm font-semibold text-stone-800 truncate">{it.title}</div>
                  {it.subtitle&&<div className="text-[11px] text-stone-500 truncate">{it.subtitle}</div>}
                </div>
                {it.value&&<div className="text-sm font-bold text-stone-700 shrink-0">{it.value}</div>}
              </div>)}
              {info.items.length>30&&<div className="px-4 py-2 text-[11px] italic text-stone-400 text-center">+{info.items.length-30} more</div>}
            </div>
          </div>}
          {info.items&&info.items.length===0&&<div className="text-center py-8 text-stone-400 text-sm italic">No items currently contribute to this number</div>}
        </div>
      </div>
    </div>}
  </KpiInfoCtx.Provider>);
}

function St({label,value,delta,trend="up",icon:Ic,breakdown}){const up=trend==="up";const ctx=useContext(KpiInfoCtx);return (<div className="bg-white rounded-2xl border border-stone-200 p-5 relative">{breakdown&&ctx&&<button onClick={()=>ctx.setInfo({label,value,...breakdown})} title="Show breakdown" className="absolute top-3 right-3 w-6 h-6 rounded-full bg-blue-50 hover:bg-blue-100 text-blue-700 flex items-center justify-center text-xs font-bold transition" aria-label={`Breakdown of ${label}`}>i</button>}<div className="flex items-start justify-between"><div><p className="text-xs text-stone-500">{label}</p><p className="text-2xl font-semibold mt-1">{value}</p></div>{Ic&&<div className={`w-9 h-9 rounded-xl bg-stone-100 flex items-center justify-center ${breakdown?"mt-7":""}`}><Ic className="w-4 h-4 text-stone-600"/></div>}</div>{delta&&<p className={`text-xs mt-3 inline-flex items-center gap-1 ${up?"text-emerald-600":"text-red-600"}`}>{up?<ArrowUpRight className="w-3 h-3"/>:<ArrowDownRight className="w-3 h-3"/>}{delta}</p>}</div>);}
function SC({title,action,children,padded=true}){return (<div className="bg-white rounded-2xl border border-stone-200"><div className="flex items-center justify-between px-5 py-4 border-b border-stone-200"><h3 className="text-sm font-semibold">{title}</h3>{action}</div><div className={padded?"p-5":""}>{children}</div></div>);}
function Pill({tone="stone",children}){const t={emerald:"bg-emerald-50 text-emerald-700 ring-emerald-200",amber:"bg-amber-50 text-amber-700 ring-amber-200",red:"bg-red-50 text-red-700 ring-red-200",blue:"bg-blue-50 text-blue-700 ring-blue-200",stone:"bg-stone-100 text-stone-700 ring-stone-200"};return (<span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[11px] font-medium ring-1 ${t[tone]}`}>{children}</span>);}
function DT({headers,rows}){return (<div className="overflow-x-auto"><table className="w-full text-sm"><thead><tr className="border-b border-stone-200">{headers.map((h,i)=>(<th key={i} className="text-left px-5 py-3 text-[11px] font-medium text-stone-500 uppercase tracking-wider">{h}</th>))}</tr></thead><tbody>{rows.map((row,i)=>(<tr key={i} className="border-b border-stone-100 hover:bg-stone-50 last:border-0">{row.map((cell,j)=>(<td key={j} className="px-5 py-3 align-middle">{cell}</td>))}</tr>))}</tbody></table></div>);}
function Area({data,color="#2563eb",height=180}){const w=600,max=Math.max(...data),min=Math.min(...data),range=max-min||1,pad=20;const pts=data.map((v,i)=>({x:(i/(data.length-1))*w,y:height-pad-((v-min)/range)*(height-pad*2)}));const line=pts.map((p,i)=>`${i===0?"M":"L"} ${p.x} ${p.y}`).join(" ");return (<svg viewBox={`0 0 ${w} ${height}`} preserveAspectRatio="none" className="w-full" style={{height}}><defs><linearGradient id="ag3" x1="0" x2="0" y1="0" y2="1"><stop offset="0%" stopColor={color} stopOpacity="0.25"/><stop offset="100%" stopColor={color} stopOpacity="0"/></linearGradient></defs><path d={`${line} L ${w} ${height} L 0 ${height} Z`} fill="url(#ag3)"/><path d={line} fill="none" stroke={color} strokeWidth="2" vectorEffect="non-scaling-stroke" strokeLinecap="round" strokeLinejoin="round"/></svg>);}
function HBar({data}){const max=Math.max(...data.map(d=>d.value));return (<div className="space-y-3">{data.map((d,i)=>(<div key={i}><div className="flex justify-between text-xs mb-1"><span className="font-medium text-stone-800">{d.label}</span><span className="text-stone-500">{d.display||d.value}</span></div><div className="h-2 bg-stone-100 rounded-full overflow-hidden"><div className="h-full rounded-full" style={{width:`${(d.value/max)*100}%`,background:d.color||"#2563eb"}}/></div></div>))}</div>);}
function Donut({data,size=140}){const total=data.reduce((s,d)=>s+d.value,0);const r=size/2-12,c=2*Math.PI*r;let off=0;return (<svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}><g transform={`translate(${size/2},${size/2}) rotate(-90)`}><circle r={r} fill="none" stroke="#f5f5f4" strokeWidth="16"/>{data.map((d,i)=>{const l=(d.value/total)*c;const el=(<circle key={i} r={r} fill="none" stroke={d.color} strokeWidth="16" strokeDasharray={`${l} ${c}`} strokeDashoffset={-off} strokeLinecap="butt"/>);off+=l;return el;})}</g><text x={size/2} y={size/2+5} textAnchor="middle" className="fill-stone-900" fontSize="18" fontWeight="600">{total}%</text></svg>);}
function PL({level}){const colors=["bg-stone-200","bg-blue-300","bg-amber-400","bg-emerald-500"];return (<div className="inline-flex items-center gap-0.5">{[0,1,2,3].map(i=>(<div key={i} className={`w-1.5 h-3 rounded-sm ${i<=level?colors[level]:"bg-stone-100"}`}/>))}</div>);}

function F({label,children,hint}){return (<div><label className="block text-xs font-medium text-stone-700 mb-1.5">{label}</label>{children}{hint&&<p className="text-[11px] text-stone-400 mt-1">{hint}</p>}</div>);}
function Inp({value,onChange,type="text",placeholder="",disabled=false}){return (<input type={type} value={value||""} placeholder={placeholder} disabled={disabled} onChange={e=>onChange(e.target.value)} className="w-full px-4 py-2.5 bg-white border border-stone-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-300 disabled:bg-stone-50"/>);}
function Sel({value,onChange,options}){return (<select value={value} onChange={e=>onChange(e.target.value)} className="w-full px-4 py-2.5 bg-white border border-stone-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-300">{options.map(o=>Array.isArray(o)?<option key={o[0]} value={o[0]}>{o[1]}</option>:<option key={o} value={o}>{o}</option>)}</select>);}
function Tog({label,checked,onChange,desc}){return (<button type="button" onClick={onChange} className={`w-full text-left flex items-center gap-3 p-3 rounded-xl cursor-pointer border transition-colors ${checked?"bg-blue-50 border-blue-200":"bg-white border-stone-200 hover:bg-stone-50"}`}><div className={`w-10 h-6 rounded-full flex items-center px-0.5 transition-colors shrink-0 ${checked?"bg-blue-600":"bg-stone-300"}`}><div className={`w-5 h-5 bg-white rounded-full shadow-sm transition-transform ${checked?"translate-x-4":""}`}/></div><div><div className="text-sm font-medium">{label}</div>{desc&&<div className="text-xs text-stone-500">{desc}</div>}</div></button>);}
function TArea({value,onChange,placeholder="",rows=3}){return (<textarea value={value||""} onChange={e=>onChange(e.target.value)} placeholder={placeholder} rows={rows} className="w-full px-4 py-2.5 bg-white border border-stone-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-300 resize-none"/>);}

/* ═══ PAGINATION HELPER ═══ */
function usePagination(data,perPage=10){
  const [page,setPage]=useState(1);
  const total=Math.ceil(data.length/perPage);
  const slice=data.slice((page-1)*perPage,page*perPage);
  const Pager=()=>total<=1?null:(<div className="flex items-center justify-between px-5 py-3 border-t border-stone-200"><span className="text-xs text-stone-500">Page {page} of {total} · {data.length} records</span><div className="flex gap-1">{Array.from({length:total},(_,i)=>(<button key={i} onClick={()=>setPage(i+1)} className={`w-8 h-8 rounded-lg text-xs font-medium ${page===i+1?"bg-blue-900 text-white":"hover:bg-stone-100"}`}>{i+1}</button>))}</div></div>);
  return {slice,Pager,page,setPage};
}

