/* ─── MINI CALENDAR ─── */
function Cal({sd,ed,setSd,setEd,sel,setSel,blocked=[]}){
  const [mo,setMo]=useState(new Date());
  const [view,setView]=useState("month"); /* month | year */
  const td=new Date();td.setHours(0,0,0,0);
  const isBlocked=(d)=>{const ds=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;return blocked.find(b=>ds>=b.start&&ds<=b.end)};
  const ck=(year,month,day)=>{
    const d=new Date(year,month,day);d.setHours(0,0,0,0);
    if(d<td||isBlocked(d))return;
    if(sel==="start"){setSd(d);setEd(null);setSel("end")}
    else{if(d<sd){setSd(d);setEd(null)}else{setEd(d);setSel("start")}}
  };

  /* Header: nav + view toggle */
  const header=<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12,gap:8}}>
    <button onClick={()=>{if(view==="month")setMo(new Date(mo.getFullYear(),mo.getMonth()-1));else setMo(new Date(mo.getFullYear()-1,mo.getMonth()))}} style={{background:"var(--g1)",border:"none",borderRadius:8,padding:6,cursor:"pointer"}}><X n="cL" s={16}/></button>
    <span style={{fontWeight:700,fontSize:14,color:"var(--navy)",flex:1,textAlign:"center"}}>{view==="month"?mo.toLocaleDateString("en-US",{month:"long",year:"numeric"}):mo.getFullYear()}</span>
    <div style={{display:"flex",gap:2,background:"var(--g1)",borderRadius:8,padding:2}}>
      <button onClick={()=>setView("month")} style={{padding:"4px 10px",borderRadius:6,fontSize:11,fontWeight:600,border:"none",cursor:"pointer",background:view==="month"?"#fff":"transparent",color:view==="month"?"var(--navy)":"var(--g5)"}}>Month</button>
      <button onClick={()=>setView("year")} style={{padding:"4px 10px",borderRadius:6,fontSize:11,fontWeight:600,border:"none",cursor:"pointer",background:view==="year"?"#fff":"transparent",color:view==="year"?"var(--navy)":"var(--g5)"}}>Year</button>
    </div>
    <button onClick={()=>{if(view==="month")setMo(new Date(mo.getFullYear(),mo.getMonth()+1));else setMo(new Date(mo.getFullYear()+1,mo.getMonth()))}} style={{background:"var(--g1)",border:"none",borderRadius:8,padding:6,cursor:"pointer"}}><X n="cR" s={16}/></button>
  </div>;

  const blockedLegend=blocked.length>0&&<div style={{display:"flex",gap:12,marginBottom:8,fontSize:11}}>
    <span style={{display:"flex",alignItems:"center",gap:4}}><span style={{width:8,height:8,borderRadius:4,background:"#F59E0B"}}/>Rented</span>
    <span style={{display:"flex",alignItems:"center",gap:4}}><span style={{width:8,height:8,borderRadius:4,background:"#DC2626"}}/>Maintenance</span>
  </div>;

  /* YEAR VIEW */
  if(view==="year"){
    return <div>
      {header}
      {blockedLegend}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8}}>
        {Array.from({length:12}).map((_,mi)=>{
          const mdim=new Date(mo.getFullYear(),mi+1,0).getDate();
          const mfd=new Date(mo.getFullYear(),mi,1).getDay();
          const mname=new Date(mo.getFullYear(),mi).toLocaleDateString("en-US",{month:"short"});
          const isCurrentM=mi===td.getMonth()&&mo.getFullYear()===td.getFullYear();
          return <div key={mi} style={{padding:8,borderRadius:10,border:isCurrentM?"2px solid var(--b4)":"1px solid var(--g2)",background:"#fff"}}>
            <button onClick={()=>{setMo(new Date(mo.getFullYear(),mi));setView("month")}} style={{background:"none",border:"none",cursor:"pointer",fontWeight:700,fontSize:12,color:isCurrentM?"var(--b6)":"var(--navy)",textAlign:"center",marginBottom:4,width:"100%",padding:0}} title={`Open ${mname}`}>{mname}</button>
            <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:1}}>
              {["S","M","T","W","T","F","S"].map((d,di)=><div key={di} style={{fontSize:8,textAlign:"center",color:"var(--g4)",fontWeight:600}}>{d}</div>)}
              {Array.from({length:mfd}).map((_,i)=><div key={"e"+i}/>)}
              {Array.from({length:mdim}).map((_,i)=>{
                const day=i+1;
                const d=new Date(mo.getFullYear(),mi,day);d.setHours(0,0,0,0);
                const past=d<td,blk=isBlocked(d),isS=same(d,sd),isE=same(d,ed),isR=sd&&ed&&inR(d,sd,ed),isT=same(d,td);
                let bg="transparent",cl="var(--g7)";
                if(past){cl="var(--g3)"}
                else if(blk){bg=blk.type==="maintenance"?"#FEE2E2":"#FEF3C7";cl=blk.type==="maintenance"?"#DC2626":"#B45309"}
                else if(isS||isE){bg="var(--b6)";cl="#fff"}
                else if(isR){bg="var(--b1)";cl="var(--b8)"}
                return <button key={day} onClick={()=>!past&&!blk&&ck(mo.getFullYear(),mi,day)} style={{width:"100%",aspectRatio:"1",display:"flex",alignItems:"center",justifyContent:"center",background:bg,color:cl,borderRadius:3,border:isT&&!blk&&!isS&&!isE?"1px solid var(--b5)":"none",cursor:past||blk?"default":"pointer",fontSize:9,fontWeight:(isS||isE||isT)?700:400,padding:0,minWidth:0}} disabled={past||blk}>{day}</button>;
              })}
            </div>
          </div>;
        })}
      </div>
    </div>;
  }

  /* MONTH VIEW */
  const dim=new Date(mo.getFullYear(),mo.getMonth()+1,0).getDate();
  const fd=new Date(mo.getFullYear(),mo.getMonth(),1).getDay();
  return <div>
    {header}
    {blockedLegend}
    <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3,textAlign:"center"}}>
      {["Su","Mo","Tu","We","Th","Fr","Sa"].map(d=><div key={d} style={{fontSize:11,fontWeight:700,color:"var(--g5)",padding:6}}>{d}</div>)}
      {Array.from({length:fd}).map((_,i)=><div key={"e"+i}/>)}
      {Array.from({length:dim}).map((_,i)=>{
        const day=i+1,d=new Date(mo.getFullYear(),mo.getMonth(),day);d.setHours(0,0,0,0);
        const past=d<td,blk=isBlocked(d),isS=same(d,sd),isE=same(d,ed),isR=sd&&ed&&inR(d,sd,ed),isT=same(d,td);
        let bg="transparent",cl="var(--g9)",br=8,fw=400,cursor="pointer";
        if(past){cl="var(--g3)";cursor="default"}
        else if(blk){bg=blk.type==="maintenance"?"#FEE2E2":"#FEF3C7";cl=blk.type==="maintenance"?"#DC2626":"#B45309";cursor="not-allowed";fw=500}
        else if(isS||isE){bg="var(--b6)";cl="#fff";fw=700}
        else if(isR){bg="var(--b1)";cl="var(--b8)";br=4}
        if(isT&&!isS&&!isE&&!blk)fw=700;
        return <button key={day} onClick={()=>!past&&!blk&&ck(mo.getFullYear(),mo.getMonth(),day)} style={{width:"100%",aspectRatio:"1",display:"flex",alignItems:"center",justifyContent:"center",background:bg,color:cl,borderRadius:br,border:"none",cursor,fontSize:13,fontWeight:fw,transition:"all .15s",position:"relative",opacity:blk?.7:1}}>{day}{isT&&!blk&&<div style={{position:"absolute",bottom:2,left:"50%",transform:"translateX(-50%)",width:4,height:4,borderRadius:2,background:isS||isE?"#fff":"var(--b5)"}}/>}{blk&&<div style={{position:"absolute",bottom:2,left:"50%",transform:"translateX(-50%)",width:6,height:6,borderRadius:3,background:blk.type==="maintenance"?"#DC2626":"#F59E0B"}}/>}</button>;
      })}
    </div>
  </div>;
}

